import React from 'react';
import { useTheme } from '../context/ThemeContext';
import profile from "../assets/images/myself_casual.jpg"
import cvPDF from "../assets/files/Pedro_CV.pdf"

const About = () => {
  const { isDarkMode } = useTheme();

  return (
    <section
      id="about"
      className={`min-h-screen py-16 px-6 sm:px-10 lg:px-20 ${isDarkMode ? "bg-gray-900" : "bg-gray-100"
        }`}
    >
      <div className="max-w-5xl mx-auto">

        <h2 className="text-3xl font-bold text-center bg-gradient-to-r from-green-400 to-blue-500 bg-clip-text text-transparent mb-14">
          About Me
        </h2>

        <div className="space-y-10">

          {/* PROFILE + INTRO */}
          <div className="flex flex-col sm:flex-row items-start gap-6">

            <img
              src={profile}
              alt="Profile"
              className="w-32 h-32 sm:w-36 sm:h-36 rounded-full object-cover shadow-xl border-4 border-white/10"
            />

            <div className={`text-base sm:text-lg leading-relaxed max-w-2xl ${isDarkMode ? "text-gray-300" : "text-gray-700"
              }`}>
              <p>
                Halo, saya seorang IT Support dengan latar belakang pendidikan di bidang IT dan memiliki ketertarikan pada pengembangan web.
                Selama masa kuliah, saya mulai mempelajari berbagai teknologi web dan mengerjakan beberapa proyek website sebagai bagian dari proses belajar.
              </p>
            </div>

          </div>

          {/* TEXT BLOCK */}
          <div className={`space-y-5 text-base sm:text-lg leading-relaxed ${isDarkMode ? "text-gray-300" : "text-gray-700"
            }`}>

            <p>
              Salah satu proyek yang pernah saya kerjakan adalah <strong>Text Emotion Analyzer</strong> yang saya publikasikan di GitHub.
              Melalui proyek tersebut, saya mencoba menggabungkan pemrosesan data dengan pengembangan aplikasi berbasis web.
            </p>

            <p>
              Saat ini saya bekerja sebagai IT Support sambil terus memperdalam kemampuan di bidang web development.
              Saya juga aktif memanfaatkan berbagai tools, termasuk teknologi AI, untuk membantu proses belajar, pengembangan, dan penyelesaian masalah.
            </p>

            <p>
              Saya selalu terbuka untuk belajar hal baru dan tertarik untuk terlibat dalam proyek yang dapat meningkatkan kemampuan teknis saya sekaligus memberikan dampak nyata.
            </p>

          </div>

          {/* BUTTON */}
          <div className="pt-2">
            <a
              href={cvPDF}
              className="inline-flex items-center gap-2 bg-gradient-to-r from-green-400 to-blue-500 text-white font-semibold py-2.5 px-7 rounded-full transition-all duration-300 hover:scale-105 hover:shadow-lg"
            >
              Download CV
            </a>
          </div>

        </div>
      </div>
    </section>
  );
};

export default About;
